+/// Test if a pair of fcmps with a shared operand and 2 constants has an
+/// empty set intersection, full set union, or if one fcmp is a superset of
+/// the other.
+static Value *simplifyAndOrOfFCmpsWithConstants(FCmpInst *Cmp0, FCmpInst *Cmp1,
+                                                bool IsAnd) {
+  // Look for this pattern: {and/or} (fcmp X, C0), (fcmp X, C1)).
+  if (Cmp0->getOperand(0) != Cmp1->getOperand(0))
+    return nullptr;
+
+  const APFloat *C0, *C1;
+  if (!match(Cmp0->getOperand(1), m_APFloat(C0)) ||
+      !match(Cmp1->getOperand(1), m_APFloat(C1)))
+    return nullptr;
+
+  // For vector types, bail out - the range logic doesn't apply cleanly.
+  if (Cmp0->getType()->isVectorTy())
+    return nullptr;
+
+  FCmpInst::Predicate Pred0 = Cmp0->getPredicate();
+  FCmpInst::Predicate Pred1 = Cmp1->getPredicate();
+
+  // Only handle the simple cases where both predicates are the same ordered
+  // comparison type. This allows us to determine subset/superset relationships.
+  if (Pred0 != Pred1)
+    return nullptr;
+
+  // Check if the constants are ordered (not NaN).
+  if (C0->isNaN() || C1->isNaN())
+    return nullptr;
+
+  // Determine the subset/superset relationship based on the predicate and
+  // constant values.
+  bool Cmp0SubsetOfCmp1 = false;
+  bool Cmp1SubsetOfCmp0 = false;
+
+  switch (Pred0) {
+  case FCmpInst::FCMP_OLT:
+    // x < C0 is subset of x < C1 iff C0 <= C1
+    if (*C0 <= *C1)
+      Cmp0SubsetOfCmp1 = true;
+    if (*C1 <= *C0)
+      Cmp1SubsetOfCmp0 = true;
+    break;
+  case FCmpInst::FCMP_OLE:
+    // x <= C0 is subset of x <= C1 iff C0 <= C1
+    if (*C0 <= *C1)
+      Cmp0SubsetOfCmp1 = true;
+    if (*C1 <= *C0)
+      Cmp1SubsetOfCmp0 = true;
+    break;
+  case FCmpInst::FCMP_OGT:
+    // x > C0 is subset of x > C1 iff C0 >= C1
+    if (*C0 >= *C1)
+      Cmp0SubsetOfCmp1 = true;
+    if (*C1 >= *C0)
+      Cmp1SubsetOfCmp0 = true;
+    break;
+  case FCmpInst::FCMP_OGE:
+    // x >= C0 is subset of x >= C1 iff C0 >= C1
+    if (*C0 >= *C1)
+      Cmp0SubsetOfCmp1 = true;
+    if (*C1 >= *C0)
+      Cmp1SubsetOfCmp0 = true;
+    break;
+  case FCmpInst::FCMP_OEQ:
+    // x == C0 and x == C1: only same if C0 == C1
+    if (*C0 == *C1) {
+      Cmp0SubsetOfCmp1 = true;
+      Cmp1SubsetOfCmp0 = true;
+    }
+    break;
+  case FCmpInst::FCMP_ONE:
+    // x != C0 and x != C1: neither is a subset unless C0 == C1
+    if (*C0 == *C1) {
+      Cmp0SubsetOfCmp1 = true;
+      Cmp1SubsetOfCmp0 = true;
+    }
+    break;
+  default:
+    // Unordered predicates have different semantics with NaN.
+    return nullptr;
+  }
+
+  // If one range is a superset of the other, simplify.
+  // For AND: take the smaller set (more restrictive).
+  // For OR: take the larger set (less restrictive).
+  if (Cmp0SubsetOfCmp1) {
+    // Cmp0 is subset of Cmp1
+    return IsAnd ? Cmp0 : Cmp1;
+  }
+  if (Cmp1SubsetOfCmp0) {
+    // Cmp1 is subset of Cmp0
+    return IsAnd ? Cmp1 : Cmp0;
+  }
+
+  return nullptr;
+}
